import argparse
import os
import time
from pathlib import Path

RETENTION_DAYS = 60


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--dry-run', action='store_true')
    args = ap.parse_args()

    allowed = (Path.cwd() / 'assets' / 'generated' / 'thumbs').resolve()
    cutoff = time.time() - RETENTION_DAYS * 24 * 60 * 60

    candidates = []
    # Broad scan then filter by string prefix
    for p in (Path.cwd() / 'assets' / 'generated').rglob('*.jpg'):
        rp = p.resolve(strict=False)
        if not str(rp).startswith(str(allowed)):
            continue
        try:
            if rp.stat().st_mtime < cutoff:
                candidates.append(rp)
        except FileNotFoundError:
            continue

    if args.dry_run:
        for p in candidates:
            print(f"DRY_RUN_DELETE: {p}")
        return

    for p in candidates:
        p.unlink(missing_ok=True)
    print(f"Deleted {len(candidates)} files")


if __name__ == '__main__':
    main()

if rp == allowed or allowed not in rp.parents:
            continue
        # extra guard: never touch thumbs_backup
        if (Path.cwd() / 'assets' / 'generated' / 'thumbs_backup') in rp.parents:
            continue

